// ============================================
// INPUT PROCESSING FUNCTIONS
// ============================================

function replacePlaceholder(prompt, placeholder, value) {
  if (!placeholder || !value) return prompt;

  // Create regex for safe replacement - escape special regex characters
  const escapedPlaceholder = placeholder.replace(/[(){}]/g, '\\$&');
  const pattern = new RegExp(escapedPlaceholder, 'g');
  return prompt.replace(pattern, value);
}

function processBlockInput(block, template) {
  let finalPrompt = template.prompt;
  const warnings = [];

  // No input handling needed
  if (!template.inputType) {
    return { prompt: finalPrompt, warnings };
  }

  // TEXT INPUT (Authority, Discount, Studies/Research)
  if (template.inputType === 'text') {
    const inputValue = block.inputValue?.trim();

    // Check if input is invalid (just numbers for Authority)
    if (block.name === 'Authority' && inputValue && /^\d+$/.test(inputValue)) {
      warnings.push(`⚠️ Authority input appears to be just a number (${inputValue}), treating as empty`);
      // Use fallback
      finalPrompt = replacePlaceholder(finalPrompt, template.placeholder, template.fallback);
    }
    // Valid input exists
    else if (inputValue) {
      finalPrompt = replacePlaceholder(finalPrompt, template.placeholder, inputValue);
    }
    // No input - use fallback or special handling
    else {
      if (block.name === 'Discount') {
        // Special case: Replace entire prompt with generic urgency
        finalPrompt = "Write a short message that creates urgency about the current offer. Focus on limited-time opportunity or special pricing, without mentioning a specific discount amount.";
        warnings.push(`ℹ️ Discount block has no input, using generic urgency prompt`);
      } else if (template.fallback) {
        // Use fallback for Authority, Studies/Research, etc.
        finalPrompt = replacePlaceholder(finalPrompt, template.placeholder, template.fallback);
        warnings.push(`ℹ️ ${block.name} has no input, using fallback: ${template.fallback}`);
      }
    }
  }

  // NUMERIC INPUT ((X) Reasons For, Listicle)
  else if (template.inputType === 'numeric') {
    const inputValue = block.inputValue?.trim();

    if (inputValue) {
      finalPrompt = replacePlaceholder(finalPrompt, template.placeholder, inputValue);
    } else {
      // Use fallback
      finalPrompt = replacePlaceholder(finalPrompt, template.placeholder, template.fallback);
      warnings.push(`ℹ️ ${block.name} has no input, using fallback: ${template.fallback}`);
    }
  }

  // SELECT INPUT (Expert Testimonial)
  else if (template.inputType === 'select') {
    const selectValue = block.selectValue?.trim();

    // Map dropdown values to natural language
    const roleMapping = {
      'User': 'satisfied customer',
      'Founder': 'company founder',
      'Expert': 'industry expert'
    };

    const role = selectValue ? (roleMapping[selectValue] || selectValue) : template.fallback;
    finalPrompt = replacePlaceholder(finalPrompt, template.placeholder, role);

    if (!selectValue) {
      warnings.push(`ℹ️ Expert Testimonial has no selection, using fallback: ${template.fallback}`);
    }
  }

  // TEXT-APPEND (Placeholder for Image)
  else if (template.inputType === 'text-append') {
    const inputValue = block.inputValue?.trim();

    if (inputValue) {
      finalPrompt += ` If the user indicated additional notes or comments, attach them as well.\n\nUSER NOTE: ${inputValue}`;
    }
  }

  return { prompt: finalPrompt, warnings };
}

// ============================================
// GLOBAL RULES DETECTION
// ============================================

const globalRules = [];
const blockNames = structureBlocks.map(b => b.name);

// Check for first-person LEDE
if (blockNames.includes("Lede (Story, First Person)") || blockNames.includes("Diary (1st Person)")) {
  globalRules.push("**CRITICAL: Write the ENTIRE advertorial in FIRST PERSON.** The narrator is a real person sharing their experience. Use 'I', 'my', 'me' throughout. Maintain this perspective consistently from headline to FAQ.");
}

// Check for Authority block
if (blockNames.includes("Authority")) {
  globalRules.push("**AUTHORITY CONSISTENCY:** An authority figure is introduced in the Authority section. Reference this person by name or role in later sections where appropriate (e.g., 'As [Name] explained...', 'The expert mentioned...').");
}

// Check for Listicle format (paired blocks)
if (blockNames.includes("Listicle (Product Comparison)")) {
  globalRules.push("**LISTICLE FORMAT:** This advertorial includes a product comparison. Maintain numbered or structured format for the comparison section. Keep evaluation criteria consistent across all products. The Listicle Intro and Product Comparison should flow seamlessly together.");
}

// Check for Expert Testimonial
if (blockNames.includes("Expert Testimonial (Quote)")) {
  globalRules.push("**EXPERT REFERENCE:** An expert testimonial is included. You may reference this expert's opinion or credentials in other sections where relevant (e.g., 'Experts recommend...', 'As verified by specialists...').");
}

// Check for Studies/Research block
if (blockNames.includes("Studies/Research")) {
  globalRules.push("**RESEARCH CREDIBILITY:** A scientific study is referenced in this advertorial. You may reference this research in other sections where relevant (e.g., 'Research shows...', 'Studies confirm...'). Maintain factual accuracy—never invent study details.");
}

// Check for Story-based narrative
const hasStoryLede = blockNames.includes("Lede (Story, First Person)") || 
                     blockNames.includes("Lede (Journalistic)") ||
                     blockNames.includes("Diary (1st Person)");
if (hasStoryLede) {
  globalRules.push("**NARRATIVE CONSISTENCY:** The advertorial opens with a narrative hook. Maintain story continuity throughout - reference the initial problem/situation in later sections when introducing solutions or benefits.");
}

// ============================================
// BUILD GLOBAL RULES SECTION
// ============================================

let globalRulesSection = '';

if (globalRules.length > 0) {
  globalRulesSection = `# GLOBAL WRITING RULES

These rules apply to the ENTIRE advertorial, not just individual sections:

${globalRules.map((rule, idx) => `${idx + 1}. ${rule}`).join('\n\n')}

---

`;

  console.log(`🎯 Detected ${globalRules.length} global writing rules`);
}

// ============================================
// BUILD STRUCTURE SECTION
// ============================================

let structureSection = `# ADVERTORIAL STRUCTURE

Write the following ${structureBlocks.length} sections **IN THIS EXACT ORDER**:

`;

const allWarnings = [];

for (const block of structureBlocks) {
  const template = blockTemplates[block.name];

  if (!template) {
    console.warn(`⚠️ Template not found for: ${block.name}`);
    allWarnings.push(`⚠️ Block "${block.name}" not found in templates - skipping`);
    continue;
  }

  // Process input and get final prompt
  const { prompt, warnings } = processBlockInput(block, template);

  // Collect warnings
  if (warnings.length > 0) {
    allWarnings.push(...warnings);
  }

  // Check for unreplaced placeholders
  if (prompt.includes('(X)') || prompt.includes('{ROLE}') || prompt.includes('{STUDY INPUT}')) {
    allWarnings.push(`⚠️ Unreplaced placeholder detected in ${block.name}`);
  }

  structureSection += `## ${block.position}. ${block.name}

${prompt}

---

`;
}

// Log all warnings
if (allWarnings.length > 0) {
  console.log('\n⚠️ WARNINGS:');
  allWarnings.forEach(w => console.log(w));
}

console.log(`✅ Built structure with ${structureBlocks.length} blocks`);

// ============================================
// RETURN
// ============================================

return [{
  json: {
    ...data,
    globalRules: globalRulesSection,
    blockStructure: structureSection,
    processingWarnings: allWarnings
  }
}];

// Extract Compliance Status for Branching
// Extracts PASS or FAIL from "**Overall Status:** PASS/FAIL"
// Also extracts violation count if present

const item = $input.first();
const output = item.json.output || '';

// Look for "**Overall Status:** PASS" or "**Overall Status:** FAIL"
const statusMatch = output.match(/\*\*Overall Status:\*\*\s*(PASS|FAIL)/i);

if (!statusMatch) {
  console.error('❌ Could not find Overall Status in output');
  console.log('Output preview:', output.substring(0, 200));

  // Default to FAIL if status cannot be determined
  return [{
    json: {
      status: 'FAIL',
      error: 'Could not parse status from Compliance output',
      raw_output: output
    }
  }];
}

const status = statusMatch[1].toUpperCase(); // Ensure uppercase

// Optionally extract violation count (useful for logging/debugging)
let violationCount = 0;
const violationMatch = output.match(/\*\*Violations Found:\*\*\s*(\d+)/i);
if (violationMatch) {
  violationCount = parseInt(violationMatch[1]);
}

console.log(`✅ Extracted status: ${status}`);
if (violationCount > 0) {
  console.log(`   Violations found: ${violationCount}`);
}

return [{
  json: {
    status: status,
    violation_count: violationCount,
    raw_output: output
  }
}];

// Cleaner + Word Counter
const rawOutput = $input.item.json.output;

let targetLength = 2000;
try {
  const writerBrief = $('Writer Brief').first().json;
  targetLength = writerBrief.campaignContent.targetLength || 2000;
} catch (e) {
  // Keep fallback
}

// Calculate acceptable range (±10% tolerance)
const minWords = Math.floor(targetLength * 0.90);
const maxWords = Math.ceil(targetLength * 1.10);

// Function to extract advertorial content (remove AI preamble if present)
function extractAdvertorial(text) {
  // Strategy 1: Split on horizontal rule (AI often uses --- to separate preamble)
  const hrSplit = text.split(/\n---+\n/);
  if (hrSplit.length > 1) {
    const firstPart = hrSplit[0];
    const metaPhrases = /ready to write|i'll craft|i will craft|based on my research|let me write|here's what i'll/i;
    if (metaPhrases.test(firstPart) && firstPart.length < 1000) {
      return hrSplit.slice(1).join('\n---\n').trim();
    }
  }

  // Strategy 2: Find first real heading (skip meta-commentary headings)
  const lines = text.split('\n');
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (/^#\s+/.test(line)) {
      const metaHeadings = /ready to write|i'll craft|i will craft|based on|let me|here's what/i;
      if (!metaHeadings.test(line)) {
        return lines.slice(i).join('\n').trim();
      }
    }
  }

  // No preamble detected, return as-is
  return text.trim();
}

// Function to count words (excludes placeholders from count)
function countWords(text) {
  let countableText = text;

  // Remove placeholders and user notes from count (but keep in content)
  countableText = countableText.replace(/\*\*Placeholder for Image.*?\*\*/gi, '');
  countableText = countableText.replace(/\*USER NOTE:.*?\*/gi, '');

  // Clean markdown formatting for accurate count
  countableText = countableText.replace(/^#+\s+/gm, '');
  countableText = countableText
    .replace(/\*\*(.+?)\*\*/g, '$1')
    .replace(/\*(.+?)\*/g, '$1')
    .replace(/`(.+?)`/g, '$1')
    .replace(/\[(.+?)\]\(.+?\)/g, '$1');

  return countableText.trim().split(/\s+/).filter(word => word.length > 0).length;
}

// Execute
const cleanContent = extractAdvertorial(rawOutput);
const wordCount = countWords(cleanContent);
const meetsRequirements = wordCount >= minWords && wordCount <= maxWords;

return {
  json: {
    // Content
    raw_output: rawOutput,
    clean_content: cleanContent,

    // Word count data (for Sanity Agent)
    word_count: wordCount,
    target_length: targetLength,
    min_words: minWords,
    max_words: maxWords,
    meets_requirements: meetsRequirements,

    // Metadata
    word_count_percentage: ((wordCount / targetLength) * 100).toFixed(1) + '%',
    words_under_over: meetsRequirements ? 0 : (wordCount < minWords ? wordCount - minWords : wordCount - maxWords),
    word_count_status: meetsRequirements ? 'PASS' : 'FAIL',

    counted_at: new Date().toISOString()
  }
};

// Code Node: "Parse Sanity Result"

const output = $input.item.json.output;
const status = output.startsWith('PASS') ? 'PASS' : 'FAIL';

return {
  json: {
    status: status,
    details: output
  }
};

// ============================================
// FILENAME BUILDER - Uses AI-extracted topic
// Format: CAMPAIGNTYPE - Topic - COUNTRY - Date
// ============================================

// Get campaign data from "Extract Fields" node
const campaignData = $('Extract Fields').first().json;

// Get AI-extracted topic from immediate previous node (AI Agent)
const aiTopic = $input.first().json;

// Extract the AI response (handle different response formats)
const extractedTopic = aiTopic.output || aiTopic.text || aiTopic.content || aiTopic;

// Campaign type abbreviation
const campaignTypeMap = {
  'Lead Generation': 'LEAD',
  'E-commerce': 'ECOM',
  'ecommerce': 'ECOM'
};
const campaignType = campaignTypeMap[campaignData.campaignType] || 'DRAFT';

// Topic from AI (fallback to niche if AI failed)
const topic = (typeof extractedTopic === 'string' ? extractedTopic.trim() : null) 
              || campaignData.niche 
              || 'Advertorial';

// Country to ISO code
const countryMap = {
  'United States': 'US',
  'United Kingdom': 'UK',
  'Canada': 'CA',
  'Germany': 'DE',
  'France': 'FR',
  'Spain': 'ES',
  'Italy': 'IT',
  'Netherlands': 'NL',
  'Australia': 'AU'
};
const country = countryMap[campaignData.country] || 'XX';

// Date (dd.mm.yyyy)
const now = new Date();
const day = String(now.getDate()).padStart(2, '0');
const month = String(now.getMonth() + 1).padStart(2, '0');
const year = now.getFullYear();
const date = `${day}.${month}.${year}`;

// Build filename
const documentName = `${campaignType} - ${topic} - ${country} - ${date}`;

console.log('📄 Generated filename:', documentName);
console.log('📊 Source data:', {
  campaignType: campaignData.campaignType,
  extractedTopic,
  country: campaignData.country
});

// Return combined data
return {
  json: {
    ...campaignData,  // All original campaign data
    aiExtractedTopic: extractedTopic,  // What AI extracted
    documentName  // Final filename
  }
};

// Code Node: "Mock Webhook Data"

return {
  json: {
    headers: {
      "content-type": "application/json"
    },
    params: {},
    query: {},
    body: {
      campaignId: "dfdbe6ae-0202-4fe2-bfd7-68875026a04c",
