      referenceUrls: [
        {
          url: "https://www.aarp.org/health/drugs-supplements/supplements-for-joint-pain-relief/",
          description: "Authoritative AARP source covering turmeric/curcumin, fish oil, and research-backed supplements. Extract: dosage recommendations, timeline expectations for results, safety warnings and drug interactions."
        },
        {
